import React, { memo } from "react";
import { Star, Quote } from "lucide-react";
import { Card, CardContent } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const TESTIMONIALS = [
  {
    text: "Põhjalik hooldus tegi auto väljanägemise paremaks kui salongist tulles.",
    author: "Marika K.",
    location: "Tallinn",
    service: "Detailing",
    source: "Google Reviews",
    rating: 5
  },
  {
    text: "Rehvitööd ja sillastend said valmis sama päeva jooksul.",
    author: "Tarmo P.",
    location: "Harjumaa",
    service: "Rehvitööd",
    source: "Google Reviews",
    rating: 5
  },
  {
    text: "Autodiagnostika Tallinnas, mis lõpuks leidis vea, mida teised ei tuvastanud.",
    author: "Kertu L.",
    location: "Tallinn",
    service: "Autodiagnostika",
    source: "Facebook",
    rating: 5
  }
];

const TestimonialsSection = memo(() => {
  return (
    <Section id="testimonials" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardContent className="py-8">
          <h2 className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100 text-center mb-8">Mida kliendid ütlevad</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {TESTIMONIALS.map((testimonial, index) => (
              <div key={index} className="rounded-3xl border border-white/40 bg-white/90 shadow-lg p-6 dark:bg-slate-900/70 dark:border-slate-800">
                <div className="flex items-center gap-1 mb-3">
                  {[...Array(testimonial.rating)].map((_, i) => (
                    <Star key={i} className="h-4 w-4 fill-yellow-400 text-yellow-400" />
                  ))}
                </div>
                <Quote className="h-6 w-6 text-slate-400 mb-3" />
                <p className="text-slate-800 dark:text-slate-300 mb-4 italic">"{testimonial.text}"</p>
                <div className="text-sm text-slate-600 dark:text-slate-400">
                  <p className="font-semibold">{testimonial.author}</p>
                  <p>{testimonial.location} • {testimonial.service}</p>
                  <p className="text-xs">{testimonial.source}</p>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

TestimonialsSection.displayName = 'TestimonialsSection';

export default TestimonialsSection;
